func calculateTotalVram(nodes []config.RunnerResponse) int {
	total := 0
	for _, n := range nodes {
		if n.Node.Status == "online" || n.Node.Status == "busy" {
			total += n.Node.MemoryAllocatedGB
		}
	}
	return total
}

